_h3:"precision mediump float;\n#define LOWPREC lowp\n// Uniforms look like they're shared between vertex and fragment shaders in GLSL, so we have to be careful to avoid name clashes\n\nuniform sampler2D gm_BaseTexture;\n\nuniform bool gm_PS_FogEnabled;\nuniform vec4 gm_FogColour;\nuniform bool gm_AlphaTestEnabled;\nuniform float gm_AlphaRefValue;\n\nvoid DoAlphaTest(vec4 SrcColour)\n{\n	if (gm_AlphaTestEnabled)\n	{\n		if (SrcColour.a <= gm_AlphaRefValue)\n		{\n			discard;\n		}\n	}\n}\n\nvoid DoFog(inout vec4 SrcColour, float fogval)\n{\n	if (gm_PS_FogEnabled)\n	{\n		SrcColour = mix(SrcColour, gm_FogColour, clamp(fogval, 0.0, 1.0)); \n	}\n}\n\n#define _YY_GLSLES_ 1\n//\n// shd_aura\n//\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nuniform float u_time;\nuniform vec4 lim;\n\nfloat noise2(vec2 uv){return fract(sin(uv.x*100.+uv.y*17.745)*63.1293);}\n\nfloat pnoise(vec2 uv)\n{\n    vec2 gv = smoothstep( 0.,1.,fract(uv) );\n    vec2 id = floor(uv);\n\n    float bl = noise2(id);\n    float br = noise2(id+vec2(1,0));\n    float b = mix(bl,br,gv.x);\n\n    float tl = noise2(id+vec2(0,1));\n    float tr = noise2(id+vec2(1,1));\n    float t = mix(tl,tr,gv.x);\n\n    float c = mix(b,t,gv.y);\n    return c;\n}\n\nfloat snoise(vec2 uv,float vel)\n{\n    uv.y -= u_time*vel;\n\n\n    float c = pnoise(uv*4.);\n    c+=pnoise(uv*8.)*.5;\n    c+=pnoise(uv*16.)*.25;\n    c+=pnoise(uv*32.)*.125;\n    c+=pnoise(uv*64.)*.0625;\n\n    c/=2.;\n    c = clamp(0.,1.,c);\n\n    return c;\n\n}\n\nvec4 aura(vec2 uv,vec3 c,float seed)\n{\n    float vel = 5.;\n\n    //shape\n    vec2 st = vec2(3.,3.5)*uv + vec2(-1.,-1.);\n\n    //fire\n    st = vec2( st.x*2.-.5 , st.y-.5 );\n\n    float d = 1.-length(st-vec2(.5,.1))*.45;\n\n    st = vec2( uv.x,uv.y ) + ((sin(u_time*.3)+1.)*.2+.5)*snoise(uv,0.);\n\n    //mask voronoi\n    float mask = snoise( st+seed,.2);\n    mask = smoothstep( 1.,1.3,d+mask );\n\n    return vec4( mix( vec3(0.),c,mask),mix(0.,1.,mask ) );\n}\n\nvoid main()\n{\n    vec2 uv = vec2( (v_vTexcoord.x - lim[0]) / (lim[2] - lim[0]) , (v_vTexcoord.y - lim[1]) / (lim[3] - lim[1]) ); \n	uv = floor(uv*100.)*1./100.;\n	uv.y = 1.-uv.y;\n    vec4 color = vec4(0.);\n\n       color  = aura(uv,vec3(0.8549, 0.0471, 0.0471),1238.);\n       color *= aura(uv,vec3(0.6314, 0.1647, 0.0235),152.);       \n       color += aura(uv,vec3(0.0941, 0.0549, 0.0),532.);\n    \n	\n    gl_FragColor = vec4( color ) + texture2D(gm_BaseTexture,v_vTexcoord) ;\n\n\n} \n",
